'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { AuthCard } from '@/components/auth/AuthCard';
import { AuthInput } from '@/components/auth/AuthInput';
import { AuthError } from '@/components/auth/AuthError';
import { loginWithEmail } from '@/services/authService';
import useAuthStore from '@/store/useAuthStore';
import { logInfo } from '@/lib/logger';

interface FormErrors {
  email?: string;
  password?: string;
}

function validate(email: string, password: string): FormErrors {
  const errors: FormErrors = {};
  if (!email.trim()) errors.email = 'Email is required.';
  else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errors.email = 'Enter a valid email address.';
  if (!password) errors.password = 'Password is required.';
  else if (password.length < 6) errors.password = 'Password must be at least 6 characters.';
  return errors;
}

export default function LoginPage() {
  const router = useRouter();
  const { setUser, setError, error } = useAuthStore();

  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [formErrors, setFormErrors] = useState<FormErrors>({});

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(null);

    const errors = validate(email, password);
    if (Object.keys(errors).length > 0) {
      setFormErrors(errors);
      return;
    }
    setFormErrors({});

    setIsLoading(true);
    try {
      logInfo('[LoginPage] Attempting login', { email });
      const user = await loginWithEmail(email, password);
      setUser(user);
      logInfo('[LoginPage] Login successful, redirecting');
      router.push('/');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Login failed.';
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <AuthCard
      title="Welcome back"
      subtitle="Sign in to your RemitlyNG account"
    >
      <form onSubmit={handleSubmit} className="flex flex-col gap-5" noValidate>
        <AuthError message={error} />

        <AuthInput
          id="email"
          label="Email address"
          type="email"
          placeholder="you@example.com"
          value={email}
          onChange={(v) => { setEmail(v); setFormErrors((p) => ({ ...p, email: undefined })); }}
          error={formErrors.email}
          disabled={isLoading}
          autoComplete="email"
        />

        <AuthInput
          id="password"
          label="Password"
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(v) => { setPassword(v); setFormErrors((p) => ({ ...p, password: undefined })); }}
          error={formErrors.password}
          disabled={isLoading}
          autoComplete="current-password"
        />

        <div className="flex items-center justify-end">
          <button type="button" className="text-[12px] text-indigo-400 hover:text-indigo-300 transition-colors">
            Forgot password?
          </button>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="flex items-center justify-center gap-2 w-full rounded-xl bg-indigo-600 px-5 py-3 text-sm font-semibold text-white transition-all duration-150 hover:bg-indigo-500 active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-600/20 mt-1"
        >
          {isLoading ? (
            <>
              <svg className="animate-spin" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <path d="M21 12a9 9 0 1 1-6.219-8.56" strokeLinecap="round"/>
              </svg>
              Signing in...
            </>
          ) : (
            'Sign in'
          )}
        </button>

        <p className="text-center text-[12.5px] text-zinc-600">
          Don&apos;t have an account?{' '}
          <Link href="/auth/register" className="text-indigo-400 hover:text-indigo-300 transition-colors font-medium">
            Create one
          </Link>
        </p>
      </form>
    </AuthCard>
  );
}
